#include <stdio.h>
#include <stdbool.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N][N];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                scanf("%d", &A[i][j]);
            }
        }
        bool found = false;
        for (int mask = 0; mask < (1 << N); mask++) {
            int y[N];
            for (int i = 0; i < N; i++) {
                y[i] = (mask >> i) & 1;
            }
            int X[N][N];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    X[i][j] = y[i] ^ y[j];
                }
            }
            bool ok = true;
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    if (A[i][j] && !X[i][j]) {
                        ok = false;
                    }
                }
            }
            if (ok) {
                for (int i = 0; i < N; i++) {
                    printf("%d ", y[i]);
                }
                printf("\n");
                found = true;
                break;
            }
        }
        if (!found) {
            printf("-1\n");
        }
    }
    return 0;
}

