import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[][] A = new int[N][N];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    A[i][j] = sc.nextInt();
                }
            }
            boolean found = false;
            for (int mask = 0; mask < (1 << N); mask++) {
                int[] y = new int[N];
                for (int i = 0; i < N; i++) {
                    y[i] = (mask >> i) & 1;
                }
                int[][] X = new int[N][N];
                for (int i = 0; i < N; i++) {
                    for (int j = 0; j < N; j++) {
                        X[i][j] = y[i] ^ y[j];
                    }
                }
                boolean ok = true;
                for (int i = 0; i < N; i++) {
                    for (int j = 0; j < N; j++) {
                        if (A[i][j] == 1 && X[i][j] == 0) {
                            ok = false;
                        }
                    }
                }
                if (ok) {
                    for (int i = 0; i < N; i++) {
                        System.out.print(y[i] + " ");
                    }
                    System.out.println();
                    found = true;
                    break;
                }
            }
            if (!found) {
                System.out.println(-1);
            }
        }
    }
}

